mapper.select:
SELECT a.id, a.project_id AS "projectId", d.id AS "detailId", d.version, d.attachments, d.solution_explanation AS "solutionExplanation", d.annotation, d.defrost_explanation AS "defrostExplanation", d.apply_defrost_at AS "applyDefrostAt", d.signature_url AS "signatureUrl", d.signed_at AS "signedAt", a.status, a.created_by AS "createdBy", a.updated_by AS "updatedBy", a.created_at AS "createdAt", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", creator.name AS "createdByName", updater.name AS "updatedByName", CASE a.status WHEN 1 THEN '待提交' WHEN 2 THEN '待确认' WHEN 3 THEN '已确认' WHEN 4 THEN '已冻结' WHEN 5 THEN '解冻中' WHEN 6 THEN '已完成' ELSE '' END AS "statusText" FROM solution_design a LEFT JOIN solution_design_detail d ON d.solution_design_id = a.id AND d.version = (SELECT MAX(sd.version) FROM solution_design_detail sd WHERE sd.solution_design_id = a.id) LEFT JOIN project p ON p.id = a.project_id LEFT JOIN sys_account creator ON creator.id = a.created_by LEFT JOIN sys_account updater ON updater.id = a.updated_by
AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND a.status = #{params.status}
ORDER BY a.updated_at DESC, a.id DESC
